                        <PrimaryButton onClick={handleTeacherSignup} disabled={loading} className="mt-4 bg-[#0066FF] hover:bg-[#0055DD]">
                            {loading ? '가입 처리 중...' : '가입 완료'}
                        </PrimaryButton>
                    </div>
