    if (mode === 'recovery') {
        return (
            <div className="flex flex-col h-full bg-[#F2F4F7] items-center justify-center p-6">
                <div className="w-full max-w-[400px] bg-white p-10 rounded-[32px] shadow-[0_20px_50px_rgba(0,0,0,0.06)] border border-white">
