-- 1. 기존 함수 삭제 (반환 타입/시그니처 변경을 위해 필수 실행)
DROP FUNCTION IF EXISTS public.get_teacher_public_info(text);
DROP FUNCTION IF EXISTS public.get_teacher_public_info(uuid);

-- 2. 컬럼 추가 및 유니크 제약 설정 (이미 실행했다면 건너뜀)
ALTER TABLE public.teachers ADD COLUMN IF NOT EXISTS class_code text;
ALTER TABLE public.teachers ADD CONSTRAINT teachers_class_code_key UNIQUE (class_code);

-- 3. 기존 선생님들에게 랜덤 4자리 코드 부여 (마이그레이션)
DO $$
DECLARE
    r RECORD;
    v_code text;
BEGIN
    FOR r IN SELECT id FROM public.teachers WHERE class_code IS NULL LOOP
        LOOP
            v_code := floor(random() * 9000 + 1000)::text;
            EXIT WHEN NOT EXISTS (SELECT 1 FROM public.teachers WHERE class_code = v_code);
        END LOOP;
        UPDATE public.teachers SET class_code = v_code WHERE id = r.id;
    END LOOP;
END $$;

-- 4. 회원가입 함수 수정 (가입 시 자동 코드 생성)
CREATE OR REPLACE FUNCTION public.signup_teacher(
    p_login_id text,
    p_password text,
    p_alias text,
    p_currency_unit text
)
RETURNS json
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_user_id uuid := gen_random_uuid();
    v_recovery_code text := upper(substring(md5(random()::text), 1, 8));
    v_class_code text;
BEGIN
    -- 이메일 중복 체크
    IF EXISTS (SELECT 1 FROM public.teachers WHERE login_id = p_login_id) THEN
        RAISE EXCEPTION '이미 가입된 이메일 계정입니다.';
    END IF;

    -- 중복되지 않는 학급 코드 생성
    LOOP
        v_class_code := floor(random() * 9000 + 1000)::text;
        EXIT WHEN NOT EXISTS (SELECT 1 FROM public.teachers WHERE class_code = v_class_code);
    END LOOP;

    -- [Step 1] teachers 테이블
    INSERT INTO public.teachers (id, login_id, password, "teacherAlias", "currencyUnit", recovery_code, class_code)
    VALUES (v_user_id, p_login_id, crypt(p_password, gen_salt('bf')), p_alias, p_currency_unit, v_recovery_code, v_class_code);

    -- [Step 2] users 테이블
    INSERT INTO public.users ("userId", name, role, teacher_id)
    VALUES (v_user_id::text, p_alias, 'teacher', v_user_id);

    -- [Step 3] accounts 테이블
    INSERT INTO public.accounts ("userId", "accountId", balance, teacher_id, "qrToken", account_type)
    VALUES (v_user_id::text, p_alias || ' 국고계좌', 0, v_user_id, encode(gen_random_bytes(16), 'hex'), 'treasury');

    INSERT INTO public.accounts ("userId", "accountId", balance, teacher_id, "qrToken", account_type)
    VALUES (v_user_id::text, p_alias || ' 마트계좌', 0, v_user_id, encode(gen_random_bytes(16), 'hex'), 'mart');

    RETURN json_build_object('success', true, 'recoveryCode', v_recovery_code, 'classCode', v_class_code);
END;
$$;

-- 5. 학생 로그인 함수 수정 (학급 코드 검증 로직 추가)
CREATE OR REPLACE FUNCTION public.login_with_password(
    p_class_code text,
    p_grade integer,
    p_class integer,
    p_number integer,
    p_password text
)
RETURNS json
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_user public.users;
    v_teacher_id uuid;
BEGIN
    -- 1. 학급 코드로 선생님 찾기
    SELECT id INTO v_teacher_id FROM public.teachers WHERE class_code = p_class_code;

    IF v_teacher_id IS NULL THEN
        RETURN json_build_object('success', false, 'message', '유효하지 않은 학급 코드입니다.');
    END IF;

    -- 2. 해당 선생님의 학생 중 정보가 일치하는 유저 찾기
    SELECT * INTO v_user FROM public.users 
    WHERE teacher_id = v_teacher_id 
    AND grade = p_grade AND class = p_class AND number = p_number AND role = 'student'
    AND password = crypt(p_password, password);

    IF v_user IS NULL THEN
        RETURN json_build_object('success', false, 'message', '학번 또는 비밀번호가 일치하지 않습니다.');
    END IF;

    RETURN json_build_object('success', true, 'user', row_to_json(v_user));
END;
$$;

-- 6. 교사 공개 정보 조회 함수 재정의 (DROP 후 재생성)
CREATE OR REPLACE FUNCTION public.get_teacher_public_info(p_teacher_id text)
RETURNS TABLE (
    currency_unit text,
    teacher_alias text,
    class_code text
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
    RETURN QUERY
    SELECT 
        "currencyUnit"::text, 
        "teacherAlias"::text,
        public.teachers.class_code::text
    FROM public.teachers
    WHERE id::text = p_teacher_id;
END;
$$;

