  // Auto-login on mount
  useEffect(() => {
    const storedUserId = localStorage.getItem('class_bank_user_id');
    if (storedUserId) {
        api.login(storedUserId).then(user => {
            if(user) setCurrentUser(user);
        }).catch(err => {
            console.error("Auto login failed", err);
            localStorage.removeItem('class_bank_user_id');
        });
    }
  }, []);

  const authContextValue = useMemo(() => ({
    currentUser,
    login: (user: User) => {
        // Save to local storage for persistence
        localStorage.setItem('class_bank_user_id', user.userId);
        setCurrentUser(user);
    },
    logout: () => {
        // 현재 유저의 역할을 명확히 확인 (closure에서 캡처된 값 사용)
        const role = currentUser?.role;
        // Role enum 또는 문자열 'student'와 비교하여 학생 여부 판단
        const isStudent = role === Role.STUDENT || role === 'student';

