요청 정보 1: transfer_funds 함수의 SQL 정의문
-- 기존에 존재할 수 있는 모든 버전의 transfer_funds 함수를 안전하게 삭제합니다.
DROP FUNCTION IF EXISTS public.transfer_funds(text, text, numeric);
DROP FUNCTION IF EXISTS public.transfer_funds(text, text, integer);
DROP FUNCTION IF EXISTS public.transfer_funds(text, text, text, integer);
DROP FUNCTION IF EXISTS public.transfer_funds(text, uuid, integer, text);
DROP FUNCTION IF EXISTS public.transfer_funds(TEXT, TEXT, INTEGER, TEXT); -- 대소문자 구분 포함

-- 가장 안정적이고 표준화된 최종 버전의 송금 함수를 생성합니다.
CREATE OR REPLACE FUNCTION public.transfer_funds(
    p_sender_user_id text,
    p_receiver_account_pk_id uuid, -- 받는 사람 계좌의 "고유 ID (PK)"를 받도록 명확히 함
    p_transfer_amount integer,
    p_memo text DEFAULT NULL
)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER -- RLS 정책을 우회하여 안전하게 실행
AS $$
DECLARE
    sender_account RECORD;
    receiver_account RECORD;
    sender_name text;
    receiver_name text;
BEGIN
    -- 1. 보내는 사람 계좌 조회
    SELECT * INTO sender_account FROM public.accounts WHERE "userId" = p_sender_user_id;
    IF NOT FOUND THEN RAISE EXCEPTION '보내는 사람의 계좌를 찾을 수 없습니다.'; END IF;

    -- 2. 잔액 확인
    IF sender_account.balance < p_transfer_amount THEN RAISE EXCEPTION '잔액이 부족합니다.'; END IF;

    -- 3. 받는 사람 계좌를 "고유 ID(PK)"로 조회 (가장 정확한 방법)
    SELECT * INTO receiver_account FROM public.accounts WHERE id = p_receiver_account_pk_id;
    IF NOT FOUND THEN RAISE EXCEPTION '받는 사람의 계좌를 찾을 수 없습니다.'; END IF;

    -- 4. 자기 자신에게 송금 방지
    IF sender_account.id = receiver_account.id THEN RAISE EXCEPTION '자기 자신에게는 송금할 수 없습니다.'; END IF;

    -- 5. 잔액 변경
    UPDATE public.accounts SET balance = balance - p_transfer_amount WHERE id = sender_account.id;
    UPDATE public.accounts SET balance = balance + p_transfer_amount WHERE id = receiver_account.id;

    -- 6. 거래 내역 기록을 위한 이름 조회
    SELECT name INTO sender_name FROM public.users WHERE "userId" = sender_account."userId";
    SELECT name INTO receiver_name FROM public.users WHERE "userId" = receiver_account."userId";

    -- 7. 양쪽 모두에게 거래 내역 기록
    INSERT INTO public.transactions ("accountId", type, amount, description, "senderId", "receiverId")
    VALUES (sender_account."accountId", 'Transfer', -p_transfer_amount, COALESCE(p_memo, receiver_name || '님에게 송금'), sender_account."userId", receiver_account."userId");

    INSERT INTO public.transactions ("accountId", type, amount, description, "senderId", "receiverId")
    VALUES (receiver_account."accountId", 'Transfer', p_transfer_amount, COALESCE(p_memo, sender_name || '님으로부터 입금'), sender_account."userId", receiver_account."userId");

    RETURN receiver_name || '님에게 ' || p_transfer_amount || '권을 성공적으로 송금했습니다.';
END;
$$;
