요청 정보 3: mart_transfer 함수의 SQL 정의문

-- 1. 기존의 중복된 함수들을 확실하게 삭제 (매개변수 타입별로 모두 삭제)
DROP FUNCTION IF EXISTS public.mart_transfer(text, integer, text);
DROP FUNCTION IF EXISTS public.mart_transfer(text, numeric, text);
DROP FUNCTION IF EXISTS public.mart_transfer(p_student_account_id text, p_amount integer, p_direction text);
DROP FUNCTION IF EXISTS public.mart_transfer(p_student_account_id text, p_amount numeric, p_direction text);

-- 2. 고유 식별자(id) 컬럼이 없는 경우를 대비해 accountId를 주 키로 사용하는 최적화된 함수 생성
CREATE OR REPLACE FUNCTION public.mart_transfer(
    p_student_account_id text,
    p_amount integer,
    p_direction text
)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_student_acc_id text;
    v_mart_acc_id text;
    v_teacher_id uuid;
    v_sender_acc text;
    v_receiver_acc text;
    v_student_name text;
BEGIN
    -- 1. 학생 계좌 및 교사 ID 찾기
    SELECT "accountId", teacher_id INTO v_student_acc_id, v_teacher_id 
    FROM public.accounts 
    WHERE "accountId" = p_student_account_id 
    LIMIT 1;

    IF v_student_acc_id IS NULL THEN
        RAISE EXCEPTION '계좌 정보를 찾을 수 없습니다. (입력된 계좌: %)', p_student_account_id;
    END IF;

    -- 2. 해당 학급의 마트 계좌 찾기
    SELECT "accountId" INTO v_mart_acc_id 
    FROM public.accounts 
    WHERE teacher_id = v_teacher_id AND account_type = 'mart'
    LIMIT 1;

    IF v_mart_acc_id IS NULL THEN
        RAISE EXCEPTION '해당 학급의 마트 계좌를 찾을 수 없습니다.';
    END IF;

    -- 3. 이체 방향 설정
    IF p_direction = 'FROM_STUDENT' THEN
        v_sender_acc := v_student_acc_id;
        v_receiver_acc := v_mart_acc_id;
    ELSE
        v_sender_acc := v_mart_acc_id;
        v_receiver_acc := v_student_acc_id;
    END IF;

    -- 4. 잔액 확인 (출금 시)
    IF (SELECT balance FROM public.accounts WHERE "accountId" = v_sender_acc) < p_amount THEN
        RAISE EXCEPTION '잔액이 부족합니다.';
    END IF;

    -- 5. 금액 이체
    UPDATE public.accounts SET balance = balance - p_amount WHERE "accountId" = v_sender_acc;
    UPDATE public.accounts SET balance = balance + p_amount WHERE "accountId" = v_receiver_acc;

    -- 6. 거래 내역 기록
    INSERT INTO public.transactions ("accountId", amount, description, type, teacher_id)
    VALUES 
        (v_sender_acc, -p_amount, '마트 결제(' || v_receiver_acc || ')', 'Mart', v_teacher_id),
        (v_receiver_acc, p_amount, '마트 수익(' || v_sender_acc || ')', 'Mart', v_teacher_id);

    RETURN '결제가 완료되었습니다.';
END;
$$;

