    let teacherId = user.role === Role.TEACHER ? user.userId : user.teacher_id;

    // 만약 학생인데 teacher_id가 없다면, DB에서 다시 한 번 조회를 시도함 (데이터 무결성 보완)
    if (!teacherId && user.role === Role.STUDENT) {
        try {
            const { data: userData } = await supabase
                .from('users')
