    v_stock_price integer;
    v_owned_quantity integer;
    v_account_id text;
    v_teacher_id uuid;
    v_volatility numeric;
    v_new_price numeric;
    v_payout numeric;
    v_impact_pct numeric;
    v_fee_rate numeric;
    v_fee_amount numeric;
