// Fix: Define StudentManagementView component which was missing
const StudentManagementView: React.FC<{ students: (User & { account: Account | null })[], refresh: () => void }> = ({ students, refresh }) => {
    const [showAddModal, setShowAddModal] = useState(false);
    const [selectedIds, setSelectedIds] = useState<string[]>([]);
    const [isDeleteMode, setIsDeleteMode] = useState(false);
    const [showQrModal, setShowQrModal] = useState(false);
    const { currentUser } = useContext(AuthContext);
    const unit = currentUser?.currencyUnit || '권';

    const handleResetPassword = async (userId: string) => {
        if (confirm('해당 학생의 비밀번호를 1234로 초기화하시겠습니까?')) {
            try {
                await api.resetPassword(userId);
                alert('비밀번호가 1234로 초기화되었습니다.');
            } catch (e: any) {
                alert(e.message);
            }
        }
    };

    const handleDelete = async () => {
        if (selectedIds.length === 0) return;
        if (confirm(`선택한 ${selectedIds.length}명의 학생을 삭제하시겠습니까? 계좌 및 모든 기록이 사라집니다.`)) {
            try {
                await api.deleteStudents(selectedIds);
                setSelectedIds([]);
                setIsDeleteMode(false);
                refresh();
            } catch (e: any) {
                alert(e.message);
            }
        }
    };

    return (
        <div className="space-y-4">
            <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-bold text-gray-800">학생 명부 관리</h3>
                <div className="flex gap-2">
                    <button onClick={() => setShowQrModal(true)} className="px-4 py-2 bg-white text-gray-700 font-bold rounded-xl border shadow-sm hover:bg-gray-50 flex items-center">
                        <QrCodeIcon className="w-5 h-5 mr-1" /> QR 인쇄
                    </button>
                    <button onClick={() => setShowAddModal(true)} className="px-4 py-2 bg-indigo-600 text-white font-bold rounded-xl shadow-lg hover:bg-indigo-700 flex items-center">
                        <UserAddIcon className="w-5 h-5 mr-1" /> 학생 추가
                    </button>
                    <button 
                        onClick={() => {
                            if (isDeleteMode && selectedIds.length > 0) handleDelete();
                            else setIsDeleteMode(!isDeleteMode);
                        }} 
                        className={`px-4 py-2 font-bold rounded-xl shadow-lg flex items-center ${isDeleteMode ? 'bg-red-600 text-white' : 'bg-white text-red-600 border'}`}
                    >
                        {isDeleteMode ? `삭제 확정 (${selectedIds.length})` : '학생 삭제'}
                    </button>
                    {isDeleteMode && <button onClick={() => { setIsDeleteMode(false); setSelectedIds([]); }} className="text-gray-400 font-bold px-2 hover:text-gray-600">취소</button>}
                </div>
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                <table className="w-full text-sm">
                    <thead className="bg-gray-50">
                        <tr>
                            {isDeleteMode && <th className="p-3 w-10"></th>}
                            <th className="p-3 text-left">번호</th>
                            <th className="p-3 text-left">이름</th>
                            <th className="p-3 text-right">잔액</th>
                            <th className="p-3 text-center">관리</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {students.map(s => (
                            <tr key={s.userId} className="hover:bg-gray-50 transition-colors">
                                {isDeleteMode && (
                                    <td className="p-3 text-center">
                                        <input 
                                            type="checkbox" 
                                            checked={selectedIds.includes(s.userId)} 
                                            onChange={() => setSelectedIds(prev => prev.includes(s.userId) ? prev.filter(id => id !== s.userId) : [...prev, s.userId])}
                                            className="w-4 h-4 text-indigo-600"
                                        />
                                    </td>
                                ) }
                                <td className="p-3 text-gray-500 font-medium">{s.grade}-{s.class} {s.number}</td>
                                <td className="p-3 font-bold text-gray-800">{s.name}</td>
                                <td className="p-3 text-right font-mono font-bold text-indigo-600">{(s.account?.balance || 0).toLocaleString()}{unit}</td>
                                <td className="p-3 text-center">
                                    <button onClick={() => handleResetPassword(s.userId)} className="text-[10px] font-bold text-gray-400 hover:text-indigo-600 border px-2 py-1 rounded-lg">비번 초기화</button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
            {showAddModal && <AddStudentModal onClose={() => setShowAddModal(false)} onComplete={refresh} />}
            {showQrModal && <QrPrintModal students={students} onClose={() => setShowQrModal(false)} />}
        </div>
    );
};

// Fix: Define JobManagementView component which was missing
const JobManagementView: React.FC<{ refresh: () => void }> = ({ refresh }) => {
    const { currentUser } = useContext(AuthContext);
    const [jobs, setJobs] = useState<Job[]>([]);
    const [loading, setLoading] = useState(true);
    const [showAddModal, setShowAddModal] = useState(false);
    const [selectedJobForAssign, setSelectedJobForAssign] = useState<Job | null>(null);
    const [students, setStudents] = useState<User[]>([]);
    const unit = currentUser?.currencyUnit || '권';

    const fetchJobsData = useCallback(async () => {
        setLoading(true);
        try {
            const data = await api.getJobs(currentUser?.userId || '');
            setJobs(data);
            const studentData = await api.getUsersByRole(Role.STUDENT, currentUser?.userId || '');
            setStudents(studentData);
        } catch (e) { console.error(e); }
        finally { setLoading(false); }
    }, [currentUser?.userId]);

    useEffect(() => { fetchJobsData(); }, [fetchJobsData]);

    const handleDeleteJob = async (id: string) => {
        if (confirm('직업을 삭제하시겠습니까? 해당 직업의 모든 배정 정보가 사라집니다.')) {
            try {
                await api.deleteJob(id);
                fetchJobsData();
            } catch (e) { console.error(e); }
        }
    };

    const handlePaySalary = async (id: string) => {
        try {
            const msg = await api.payJobSalary(id);
            alert(msg);
            fetchJobsData();
            refresh();
        } catch (e: any) { alert(e.message); }
    };

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h3 className="text-xl font-bold text-gray-800">직업 및 월급 관리</h3>
                <div className="flex gap-2">
                    <button onClick={async () => {
                        if(confirm('모든 직업의 월급과 인센티브를 일괄 지급하시겠습니까?')) {
                            try {
                                const msg = await api.payAllSalaries();
                                alert(msg);
                                fetchJobsData();
                                refresh();
                            } catch(e: any) { alert(e.message); }
                        }
                    }} className="px-4 py-2 bg-indigo-600 text-white font-bold rounded-xl shadow-lg hover:bg-indigo-700 flex items-center">
                         일괄 월급 지급
                    </button>
                    <button onClick={() => setShowAddModal(true)} className="px-4 py-2 bg-white text-gray-700 font-bold rounded-xl border shadow-sm hover:bg-gray-50 flex items-center">
                        <PlusIcon className="w-5 h-5 mr-1" /> 직업 추가
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {jobs.map(job => (
                    <div key={job.id} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col group">
                        <div className="flex justify-between items-start mb-4">
                            <div>
                                <h4 className="font-black text-lg text-gray-900">{job.jobName}</h4>
                                <p className="text-xs text-gray-400 mt-1 line-clamp-1">{job.description}</p>
                            </div>
                            <button onClick={() => handleDeleteJob(job.id)} className="p-2 text-gray-300 hover:text-red-500 transition-colors">
                                <XIcon className="w-5 h-5" />
                            </button>
                        </div>
                        <div className="flex justify-between items-center mb-6 bg-gray-50 p-3 rounded-xl">
                            <div>
                                <span className="text-[10px] text-gray-400 font-bold uppercase block">기본 월급</span>
                                <span className="font-black text-indigo-600">{job.salary.toLocaleString()}{unit}</span>
                            </div>
                            <div className="text-right">
                                <span className="text-[10px] text-gray-400 font-bold uppercase block">인센티브</span>
                                <span className="font-black text-orange-500">{job.incentive.toLocaleString()}{unit}</span>
                            </div>
                        </div>
                        <div className="mb-6 flex-grow">
                            <span className="text-[10px] text-gray-400 font-bold uppercase mb-2 block">배정된 학생 ({job.assigned_students?.length || 0}명)</span>
                            <div className="flex flex-wrap gap-1.5">
                                {job.assigned_students?.map(s => (
                                    <span key={s.userId} className="px-2.5 py-1 bg-blue-50 text-blue-700 text-[10px] font-black rounded-lg border border-blue-100">{s.name}</span>
                                ))}
