                            </div>
                        </div>
                        <button onClick={() => handlePaySalary(job.id)} className="w-full py-3 bg-[#2B548F] text-white font-bold rounded-xl text-sm hover:bg-[#234576] active:scale-95 transition-all shadow-md shadow-blue-50">
                            월급 지급하기
                        </button>
                    </div>
                ))}
            </div>

            {showAddModal && <AddJobModal onClose={() => setShowAddModal(false)} onComplete={fetchJobsData} />}
            {selectedJobForAssign && <AssignJobModal job={selectedJobForAssign} students={students} onClose={() => setSelectedJobForAssign(null)} onComplete={fetchJobsData} />}
        </div>
    );
};

