                </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {taxes.map(tax => {
                    const paidCount = tax.recipients.filter(r => r.isPaid).length;
                    const totalCount = tax.recipients.length;
                    const progress = totalCount > 0 ? (paidCount / totalCount) * 100 : 0;
                    const dDay = getDDay(tax.dueDate);

                    return (
                        <div key={tax.id} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col group">
                            <div className="flex justify-between items-start mb-4">
                                <div>
                                    <h4 className="font-black text-lg text-gray-900">{tax.name}</h4>
                                    <p className="text-[10px] text-gray-400 font-bold uppercase mt-1">납부 기한: {new Date(tax.dueDate).toLocaleDateString()}</p>
                                </div>
                                <button onClick={() => handleDeleteTax(tax.id)} className="p-1 text-gray-300 hover:text-red-500 transition-colors"><XIcon className="w-5 h-5"/></button>
                            </div>

                            <div className="flex justify-between items-center mb-6">
                                <div className="text-2xl font-black text-red-600">{tax.amount.toLocaleString()}{unit}</div>
