    );
};

// Fix: Define FundManagementView component which was missing
const FundManagementView: React.FC<{ students: User[] }> = ({ students }) => {
    const { currentUser } = useContext(AuthContext);
    const [funds, setFunds] = useState<Fund[]>([]);
    const [loading, setLoading] = useState(true);
    const [showAddModal, setShowAddModal] = useState(false);
    const [selectedFundForInvestors, setSelectedFundForInvestors] = useState<Fund | null>(null);
    const unit = currentUser?.currencyUnit || '권';

    const fetchFundsData = useCallback(async () => {
        setLoading(true);
        try {
            const data = await api.getFunds(currentUser?.userId || '');
            setFunds(data);
        } catch(e) { console.error(e); }
        finally { setLoading(false); }
    }, [currentUser?.userId]);

    useEffect(() => { fetchFundsData(); }, [fetchFundsData]);

    const handleSettle = async (fundId: string, status: FundStatus) => {
        if(confirm(`정말로 이 펀드를 '${status === FundStatus.SUCCESS ? '성공' : '실패'}' 처리하시겠습니까? 원금 및 배당금이 정산됩니다.`)) {
            try {
                const msg = await api.settleFund(fundId, status);
                alert(msg);
                fetchFundsData();
            } catch(e: any) { alert(e.message); }
        }
    };

    const handleDeleteFund = async (id: string) => {
        if(confirm('펀드 상품을 삭제하시겠습니까?')) {
            try {
                await api.deleteFund(id);
                fetchFundsData();
            } catch(e) { console.error(e); }
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h3 className="text-xl font-bold text-gray-800">펀드 상품 관리</h3>
                <button onClick={() => setShowAddModal(true)} className="px-4 py-2 bg-indigo-600 text-white font-bold rounded-xl shadow-lg hover:bg-indigo-700 flex items-center">
                    <NewFundIcon className="w-5 h-5 mr-1" /> 펀드 등록하기
                </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {funds.map(fund => (
                    <div key={fund.id} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col group">
                        <div className="flex justify-between items-start mb-4">
                            <div>
                                <h4 className="font-black text-lg text-gray-900">{fund.name}</h4>
                                <p className="text-[10px] text-indigo-600 font-bold uppercase mt-1">기획자: {fund.creatorName || '알 수 없음'}</p>
                            </div>
                            <div className="flex gap-2">
                                <button onClick={() => setSelectedFundForInvestors(fund)} className="p-2 text-gray-300 hover:text-indigo-600 transition-colors"><ManageIcon className="w-5 h-5"/></button>
                                <button onClick={() => handleDeleteFund(fund.id)} className="p-2 text-gray-300 hover:text-red-500 transition-colors"><XIcon className="w-5 h-5"/></button>
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-2 mb-6 text-center">
                            <div className="bg-gray-50 p-2 rounded-xl border border-gray-100">
                                <span className="text-[8px] text-gray-400 font-bold block uppercase">현재 모금액</span>
                                <span className="font-black text-indigo-700">{(fund.totalInvestedAmount || 0).toLocaleString()}{unit}</span>
                            </div>
                            <div className="bg-gray-50 p-2 rounded-xl border border-gray-100">
                                <span className="text-[8px] text-gray-400 font-bold block uppercase">투자자</span>
                                <span className="font-black text-gray-900">{fund.investorCount || 0}명</span>
                            </div>
                        </div>

                        <div className="flex gap-2 mt-auto">
                            {fund.status === FundStatus.RECRUITING || fund.status === FundStatus.ONGOING ? (
                                <>
                                    <button onClick={() => handleSettle(fund.id, FundStatus.SUCCESS)} className="flex-1 py-3 bg-indigo-600 text-white font-black rounded-xl text-xs hover:bg-indigo-700 transition-all">성공 (정산)</button>
                                    <button onClick={() => handleSettle(fund.id, FundStatus.FAIL)} className="flex-1 py-3 bg-red-50 text-red-600 font-black rounded-xl text-xs hover:bg-red-100 transition-all">실패 (반환)</button>
                                </>
                            ) : (
                                <div className="w-full py-3 bg-gray-100 text-gray-400 text-center font-black rounded-xl text-xs">정산 완료 ({fund.status})</div>
                            )}
                        </div>
                    </div>
                ))}
            </div>
            {showAddModal && <AddFundModal students={students} onClose={() => setShowAddModal(false)} onComplete={fetchFundsData} />}
            {selectedFundForInvestors && <FundInvestorsModal fund={selectedFundForInvestors} onClose={() => setSelectedFundForInvestors(null)} />}
        </div>
    );
};

