const DashboardView: React.FC<{ students: (User & { account: Account | null })[], refresh: () => void }> = ({ students, refresh }) => {
    const { currentUser } = useContext(AuthContext);
    const [treasury, setTreasury] = useState<Account | null>(null);
    const [issueAmount, setIssueAmount] = useState('');
    const unit = currentUser?.currencyUnit || '권';

    useEffect(() => {
        api.getTeacherAccount().then(setTreasury);
    }, []);

    const handleIssue = async () => {
        if (!issueAmount || !currentUser) return;
        try {
            await api.issueCurrency(currentUser.userId, parseInt(issueAmount));
            alert('화폐가 발행되었습니다.');
            setIssueAmount('');
            api.getTeacherAccount().then(setTreasury);
        } catch (e: any) { alert(e.message); }
    };

    const totalStudentBalance = students.reduce((sum, s) => sum + (s.account?.balance || 0), 0);

    return (
        <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                    <p className="text-xs font-black text-gray-400 mb-2 uppercase">국고 잔액</p>
                    <p className="text-3xl font-black text-indigo-600">{(treasury?.balance || 0).toLocaleString()}{unit}</p>
                </div>
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                    <p className="text-xs font-black text-gray-400 mb-2 uppercase">학생 총 예치금</p>
                    <p className="text-3xl font-black text-gray-900">{totalStudentBalance.toLocaleString()}{unit}</p>
                </div>
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                    <p className="text-xs font-black text-gray-400 mb-2 uppercase">등록 학생 수</p>
                    <p className="text-3xl font-black text-gray-900">{students.length}명</p>
                </div>
            </div>

            <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
                <h3 className="text-lg font-black text-gray-900 mb-6">화폐 발행 (국고 충전)</h3>
                <div className="flex gap-4">
                    <input 
                        type="number" 
                        value={issueAmount} 
                        onChange={e => setIssueAmount(e.target.value)} 
