// Fix: Implementation of JobManagementView
const JobManagementView: React.FC<{ refresh: () => void }> = ({ refresh }) => {
    const { currentUser } = useContext(AuthContext);
    const [jobs, setJobs] = useState<Job[]>([]);
    const [loading, setLoading] = useState(true);
    const unit = currentUser?.currencyUnit || '권';

    const fetchJobs = useCallback(async () => {
        if (!currentUser) return;
        setLoading(true);
        try {
            const data = await api.getJobs(currentUser.userId);
            setJobs(data);
        } finally { setLoading(false); }
    }, [currentUser]);

    useEffect(() => { fetchJobs(); }, [fetchJobs]);

    const handlePayAll = async () => {
        if (!window.confirm('모든 직업의 월급을 일괄 지급하시겠습니까?')) return;
        try {
            const msg = await api.payAllSalaries();
            alert(msg);
            fetchJobs();
            refresh();
        } catch (e: any) { alert(e.message); }
    };

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h3 className="text-xl font-black text-gray-900">직업 및 월급 관리</h3>
                <div className="flex gap-2">
                    <button onClick={handlePayAll} className="px-5 py-2.5 bg-green-600 text-white font-black rounded-xl shadow-lg shadow-green-100 flex items-center gap-2">
                         월급 일괄 지급
                    </button>
                    <button className="px-5 py-2.5 bg-indigo-600 text-white font-black rounded-xl shadow-lg shadow-indigo-100 flex items-center gap-2">
                        <PlusIcon className="w-5 h-5" /> 직업 추가
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {jobs.map(job => (
                    <div key={job.id} className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 flex flex-col">
                        <div className="flex justify-between items-start mb-4">
                            <div>
                                <h4 className="font-black text-lg text-gray-900">{job.jobName}</h4>
                                <p className="text-xs text-gray-400 font-bold">{job.description}</p>
                            </div>
                            <div className="text-right">
                                <div className="text-[10px] text-gray-400 font-black uppercase">월급</div>
                                <div className="font-black text-indigo-600 text-xl">{job.salary.toLocaleString()}{unit}</div>
                            </div>
                        </div>
                        <div className="flex flex-wrap gap-1 mb-6">
                            {job.assigned_students.map(s => (
                                <span key={s.userId} className="px-2 py-1 bg-gray-100 text-gray-600 text-[10px] font-bold rounded-lg">{s.name}</span>
                            ))}
                            {job.assigned_students.length === 0 && <span className="text-[10px] text-gray-300 font-bold italic">배정된 학생 없음</span>}
                        </div>
                        <button 
                            onClick={async () => {
                                try {
                                    const msg = await api.payJobSalary(job.id);
                                    alert(msg);
                                    fetchJobs(); refresh();
                                } catch(e: any) { alert(e.message); }
                            }}
                            className="mt-auto w-full py-3 bg-gray-50 text-gray-800 font-black rounded-2xl hover:bg-indigo-50 hover:text-indigo-600 transition-all border border-transparent hover:border-indigo-100"
